const input = $json.body ?? $json;
const requestId = String(input.request_id ?? '').trim();
const valid = /^[0-9a-f]{8}-[0-9a-f]{4}-[1-5][0-9a-f]{3}-[89ab][0-9a-f]{3}-[0-9a-f]{12}$/i.test(requestId);
return [{json:{
  ok: valid,
  request_id: requestId,
  error: valid ? null : {code:'INVALID_REQUEST_ID',message:'request_id غير صالح.'}
}}];

const payload = $json;

let row = null;

if (Array.isArray(payload)) {
  row = payload[0] ?? null;
} else if (Array.isArray(payload?.data)) {
  row = payload.data[0] ?? null;
} else if (payload && typeof payload === 'object' && payload.id) {
  row = payload;
}

if (!row) {
  return [{
    json: {
      ok: false,
      http_status: 404,
      error: {
        code: 'REQUEST_NOT_FOUND',
        message: 'طلب الحملة غير موجود.'
      }
    }
  }];
}

const resolverStatus = row.request_payload?.resolver_status;

if (resolverStatus !== 'resolved') {
  return [{
    json: {
      ok: false,
      http_status: 409,
      error: {
        code: 'POST_NOT_RESOLVED',
        message: 'يجب حل معرّف المنشور الموجود قبل توليد الاستراتيجية.'
      },
      request: row
    }
  }];
}

return [{
  json: {
    ok: true,
    http_status: 200,
    request: row
  }
}];

const payload = $json;

let rows = [];

if (Array.isArray(payload)) {
  rows = payload;
} else if (Array.isArray(payload?.data)) {
  rows = payload.data;
} else if (payload && typeof payload === 'object' && payload.insight_date) {
  rows = [payload];
}

const num = v => Number(v ?? 0);
const sum = key => rows.reduce((a, r) => a + num(r[key]), 0);

const weightedAvg = (key, weightKey) => {
  const totalW = rows.reduce((a, r) => a + num(r[weightKey]), 0);
  if (!totalW) return 0;

  return rows.reduce(
    (a, r) => a + (num(r[key]) * num(r[weightKey])),
    0
  ) / totalW;
};

const spend = sum('spend');
const conversations = sum('messaging_conversations');
const impressions = sum('impressions');
const clicks = sum('clicks');

return [{
  json: {
    period_days: 90,
    rows_count: rows.length,
    spend: Number(spend.toFixed(2)),
    conversations,
    impressions,
    clicks,
    avg_cost_per_conversation:
      conversations
        ? Number((spend / conversations).toFixed(4))
        : null,
    ctr:
      impressions
        ? Number(((clicks / impressions) * 100).toFixed(4))
        : 0,
    avg_frequency:
      Number(weightedAvg('frequency', 'impressions').toFixed(4)),
    avg_cpm:
      impressions
        ? Number(((spend / impressions) * 1000).toFixed(4))
        : null,
    avg_cpc:
      clicks
        ? Number((spend / clicks).toFixed(4))
        : null
  }
}];

const req = $('Validate Request').first().json.request;
const perf = $json;
const payload = req.request_payload ?? {};
const providedContent = payload.content_context ?? {};

let selectedContent = null;

try {
  const loadedItems = $('Load Selected Content').all();

  for (const item of loadedItems) {
    const value = item.json;

    if (Array.isArray(value) && value.length) {
      selectedContent = value[0];
      break;
    }

    if (Array.isArray(value?.data) && value.data.length) {
      selectedContent = value.data[0];
      break;
    }

    if (value && typeof value === 'object' && value.id) {
      selectedContent = value;
      break;
    }
  }
} catch {}

const content = {
  caption: selectedContent?.caption ?? providedContent.caption ?? null,
  description: providedContent.description ?? null,
  media_type:
    selectedContent?.content_type ??
    selectedContent?.media_type ??
    providedContent.media_type ??
    payload.detected_content_type ??
    null,
  product_name: providedContent.product_name ?? null,
  offer: providedContent.offer ?? null,
  visual_summary: providedContent.visual_summary ?? null,
  thumbnail_url:
    selectedContent?.thumbnail_url ??
    providedContent.thumbnail_url ??
    null,
  media_url: selectedContent?.media_url ?? providedContent.media_url ?? null,
  permalink:
    selectedContent?.permalink ??
    providedContent.permalink ??
    req.source_post_url ??
    null,
  likes_count: Number(
    selectedContent?.likes_count ??
    providedContent.likes_count ??
    0
  ),
  comments_count: Number(
    selectedContent?.comments_count ??
    providedContent.comments_count ??
    0
  ),
  shares_count: Number(
    selectedContent?.shares_count ??
    providedContent.shares_count ??
    0
  ),
  evidence_level:
    selectedContent || Object.keys(providedContent).length
      ? 'provided'
      : 'limited'
};

return [{
  json: {
    request_id: req.id,
    business: {
      name: 'White Style',
      niche: 'Fashion and apparel retail',
      market: 'Palestine',
      currency: 'USD',
      primary_destination: req.destination_type,
      min_daily_budget: 5,
      max_daily_budget: 25
    },
    campaign_request: {
      target_ad_account_id: req.target_ad_account_id,
      target_meta_account_id: req.target_meta_account_id,
      source_platform: req.source_platform,
      source_post_url: req.source_post_url,
      requested_daily_budget: req.requested_daily_budget,
      execution_mode: req.execution_mode,
      resolved_identifiers: {
        source_post_id:
          payload.source_post_id ??
          selectedContent?.meta_post_id ??
          null,
        object_story_id: payload.object_story_id ?? null,
        instagram_media_id:
          payload.instagram_media_id ??
          selectedContent?.instagram_media_id ??
          null
      }
    },
    selected_content: {
      content_library_id:
        selectedContent?.id ??
        payload.content_library_id ??
        null,
      platform:
        selectedContent?.platform ??
        req.source_platform,
      content_type:
        selectedContent?.content_type ??
        payload.detected_content_type ??
        null,
      meta_post_id:
        selectedContent?.meta_post_id ??
        payload.source_post_id ??
        null,
      instagram_media_id:
        selectedContent?.instagram_media_id ??
        payload.instagram_media_id ??
        null,
      page_id:
        selectedContent?.page_id ??
        payload.page_id ??
        null,
      permalink:
        selectedContent?.permalink ??
        req.source_post_url,
      caption:
        selectedContent?.caption ??
        providedContent.caption ??
        null,
      thumbnail_url:
        selectedContent?.thumbnail_url ??
        providedContent.thumbnail_url ??
        null,
      media_url:
        selectedContent?.media_url ??
        providedContent.media_url ??
        null,
      engagement: {
        likes: Number(
          selectedContent?.likes_count ??
          providedContent.likes_count ??
          0
        ),
        comments: Number(
          selectedContent?.comments_count ??
          providedContent.comments_count ??
          0
        ),
        shares: Number(
          selectedContent?.shares_count ??
          providedContent.shares_count ??
          0
        )
      }
    },
    content_evidence: content,
    historical_performance: perf,
    hard_rules: {
      daily_budget_min: 5,
