const response = $json;

if (response?.error) {
  const errorMessage =
    response.error?.message ??
    response.error?.error?.message ??
    JSON.stringify(response.error);

  throw new Error(
    `Content Analyst API failed: ${errorMessage}`
  );
}

function extractText(value) {
  if (typeof value?.output_text === 'string') {
    return value.output_text;
  }

  for (const output of value?.output ?? []) {
    for (const content of output?.content ?? []) {
      if (typeof content?.text === 'string') {
        return content.text;
      }

      if (content?.type === 'output_text' && typeof content?.text === 'string') {
        return content.text;
      }
    }
  }

  return null;
}

const text = extractText(response);

if (!text) {
  throw new Error(
    `Content Analyst returned no structured output. Response: ${JSON.stringify(response).slice(0, 1000)}`
  );
}

let parsed;

try {
  parsed = JSON.parse(text);
} catch {
  throw new Error(
    `Content Analyst returned invalid JSON: ${text.slice(0, 1000)}`
  );
}

return [{ json: parsed }];

