const response = $json;
function extract(r) {
  if (typeof r.output_text === 'string') return r.output_text;
  for (const out of (r.output ?? [])) {
    for (const c of (out.content ?? [])) {
      if (typeof c.text === 'string') return c.text;
    }
  }
  return null;
}
const text = extract(response);
if (!text) throw new Error('Safety Reviewer returned no structured output');
let parsed;
try { parsed = JSON.parse(text); }
catch (e) { throw new Error('Safety Reviewer returned invalid JSON: ' + text.slice(0,300)); }
return [{json:parsed}];

const request = $('Validate Request').first().json.request;
const content = $('Parse Content Analysis').first().json;
const history = $('Parse Historical Analysis').first().json;
const audience = $('Parse Audience Plan').first().json;
const budget = $('Parse Budget Plan').first().json;
const proposal = $('Parse Campaign Strategy').first().json;
const safety = $('Parse Safety Review').first().json;
const now = new Date().toISOString();

let persistedStrategies = [];
try { persistedStrategies = $('Upsert Campaign Strategies').all(); } catch {}

const payload = {
  ...(request.request_payload ?? {}),
  strategy_status: safety.approved ? 'ready' : 'needs_review',
  strategy_generated_at: now,
  strategy_completed_at: now,
  content_analysis: content,
  historical_analysis: history,
  audience_plan: audience,
  budget_plan: budget,
  campaign_strategy: proposal,
  safety_review: safety,
  selected_strategy_tier: safety.recommended_tier,
  persisted_strategy_count: persistedStrategies.length,
  initial_meta_status: 'PAUSED',
  strategist_version: 'ws-03-async-v1'
};

return [{json:{
  request_id:request.id,
  approved:safety.approved,
  patch:{
    status:safety.approved ? 'strategy_ready' : 'strategy_review_required',
    error_code:safety.approved ? null : 'STRATEGY_REVIEW_REQUIRED',
    error_message:safety.approved ? null : (safety.violations ?? []).join(' | '),
    request_payload:payload
  }
}}];

const raw = $json;

let row = null;

if (Array.isArray(raw)) {
  row = raw[0] ?? null;
} else if (Array.isArray(raw?.data)) {
  row = raw.data[0] ?? null;
} else if (raw && typeof raw === 'object') {
  row = raw;
}

const p = row?.request_payload ?? {};

let strategies = [];

try {
  strategies = $('Upsert Campaign Strategies')
    .all()
    .flatMap(item => {
      if (Array.isArray(item.json)) return item.json;
      if (Array.isArray(item.json?.data)) return item.json.data;
      return item.json?.id ? [item.json] : [];
    });
} catch {}

return [{
  json: {
    ok: row?.status === 'strategy_ready',
    request_id: row?.id ?? null,
    status: row?.status ?? null,
    recommended_tier: p.selected_strategy_tier ?? null,
    persisted_strategy_count: strategies.length,
    strategies,
    safety_review: p.safety_review ?? null,
    completed_at: new Date().toISOString()
  }
}];

return [{json:{
  ok:false,
  http_status:$json.http_status ?? 400,
  error_code:$json.error?.code ?? 'STRATEGY_REQUEST_FAILED',
  error_message:$json.error?.message ?? 'تعذر توليد استراتيجية الحملة.'
}}];

const request = $('Validate Request').first().json.request;
const proposal = $('Parse Campaign Strategy').first().json;
const safety = $('Parse Safety Review').first().json;

const expectedTiers = ['conservative', 'balanced', 'aggressive'];
const rawStrategies = Array.isArray(proposal.strategies)
  ? proposal.strategies
  : [];

const normalizedStrategies = rawStrategies.map((strategy) => ({
  ...strategy,
  tier: String(strategy?.tier ?? '').trim().toLowerCase()
}));

const receivedTiers = normalizedStrategies.map((strategy) => strategy.tier);
const uniqueTiers = [...new Set(receivedTiers)];

const missingTiers = expectedTiers.filter(
  (tier) => !uniqueTiers.includes(tier)
);

const duplicateTiers = uniqueTiers.filter(
  (tier) => receivedTiers.filter((value) => value === tier).length > 1
);

const unsupportedTiers = uniqueTiers.filter(
  (tier) => !expectedTiers.includes(tier)
);

if (
  normalizedStrategies.length !== 3 ||
  uniqueTiers.length !== 3 ||
  missingTiers.length ||
  duplicateTiers.length ||
  unsupportedTiers.length
) {
  throw new Error(
    [
      'INVALID_STRATEGY_TIERS',
      `Expected exactly: ${expectedTiers.join(', ')}`,
      `Received: ${receivedTiers.join(', ') || 'none'}`,
      missingTiers.length
        ? `Missing: ${missingTiers.join(', ')}`
        : null,
      duplicateTiers.length
        ? `Duplicates: ${duplicateTiers.join(', ')}`
        : null,
      unsupportedTiers.length
        ? `Unsupported: ${unsupportedTiers.join(', ')}`
        : null
    ].filter(Boolean).join(' | ')
  );
}

const strategyByTier = Object.fromEntries(
  normalizedStrategies.map((strategy) => [strategy.tier, strategy])
);

const selectedTierCandidate = String(
  safety.recommended_tier ??
  proposal.recommended_tier ??
  'balanced'
).trim().toLowerCase();

const selectedTier = expectedTiers.includes(selectedTierCandidate)
  ? selectedTierCandidate
  : 'balanced';

const warnings = Array.isArray(safety.warnings)
  ? safety.warnings
  : [];

const requiredChecks = Array.isArray(safety.required_human_checks)
  ? safety.required_human_checks
  : [];

const rows = expectedTiers.map((tier) => {
  const strategy = strategyByTier[tier];

  const ageMin = Number(strategy.age_min);
  const ageMax = Number(strategy.age_max);
  const dailyBudget = Number(strategy.daily_budget);
  const durationDays = Number(strategy.duration_days);
  const confidence = Number(strategy.confidence ?? 0);

  if (
    !Number.isFinite(dailyBudget) ||
    dailyBudget < 5 ||
    dailyBudget > 25
  ) {
    throw new Error(
      `INVALID_DAILY_BUDGET | tier=${tier} | value=${strategy.daily_budget}`
    );
  }

  if (
    !Number.isInteger(durationDays) ||
    durationDays < 3 ||
    durationDays > 14
  ) {
    throw new Error(
      `INVALID_DURATION | tier=${tier} | value=${strategy.duration_days}`
    );
  }

  if (
    !Number.isInteger(ageMin) ||
    !Number.isInteger(ageMax) ||
    ageMin < 18 ||
    ageMax > 65 ||
    ageMax < ageMin
  ) {
    throw new Error(
      `INVALID_AGE_RANGE | tier=${tier} | age_min=${strategy.age_min} | age_max=${strategy.age_max}`
    );
  }

  return {
    organization_id: request.organization_id,
    request_id: request.id,
    target_ad_account_id: request.target_ad_account_id,
    tier,
    campaign_name: proposal.campaign_name,
    objective: proposal.objective,
    optimization_goal: proposal.optimization_goal,
    billing_event: proposal.billing_event ?? 'IMPRESSIONS',
    bid_strategy: proposal.bid_strategy ?? 'LOWEST_COST_WITHOUT_CAP',
    destination_type: proposal.destination_type,
    daily_budget: dailyBudget,
    duration_days: durationDays,
    age_min: ageMin,
    age_max: ageMax,
    gender: strategy.gender,
    country_codes: Array.isArray(strategy.country_codes)
      ? strategy.country_codes
      : ['PS'],
    placements: Array.isArray(strategy.placements)
      ? strategy.placements
      : [],
    targeting_mode: strategy.targeting_mode ?? null,
    interest_hints: Array.isArray(strategy.interest_hints)
      ? strategy.interest_hints
      : [],
    confidence,
    reasons: Array.isArray(strategy.reasons)
      ? strategy.reasons
      : [],
    safety_warnings: [...warnings, ...requiredChecks],
    strategy_payload: {
      ...strategy,
      tier,
      campaign_name: proposal.campaign_name,
      objective: proposal.objective,
      optimization_goal: proposal.optimization_goal,
      billing_event: proposal.billing_event,
      bid_strategy: proposal.bid_strategy,
      destination_type: proposal.destination_type,
      content_analysis_summary: proposal.content_analysis_summary,
      historical_analysis_summary: proposal.historical_analysis_summary,
      safety_review: safety
    },
    selected: false,
    status: 'proposed',
    build_error_code: null,
    build_error_message: null
  };
});

return rows.map((row) => ({ json: row }));

const request = $('Validate Request').first().json.request;
const status = String(request.status ?? 'draft');

const blockedStatuses = [
  'analyzing',
  'strategy_ready',
  'strategy_review_required',
  'building',
  'ready_for_review',
  'approved',
  'published'
];

const shouldStart = !blockedStatuses.includes(status);

return [{
  json: {
    should_start: shouldStart,
    request_id: request.id,
    current_status: status,
    request,
    response: shouldStart
      ? null
      : {
          ok: true,
          accepted: false,
          duplicate_execution_prevented: true,
          request_id: request.id,
          status,
          message:
            status === 'analyzing'
              ? 'توليد الاستراتيجية قيد التنفيذ بالفعل.'
              : 'تم توليد الاستراتيجية أو الانتقال إلى مرحلة لاحقة مسبقًا.'
        }
  }
}];

const request = $('Validate Request').first().json.request;
const now = new Date().toISOString();

return [{
  json: {
    request_id: request.id,
    patch: {
      status: 'analyzing',
      error_code: null,
      error_message: null,
      request_payload: {
        ...(request.request_payload ?? {}),
        strategy_status: 'analyzing',
        strategy_started_at: now,
        strategy_completed_at: null,
        strategist_version: 'ws-03-async-v1'
      }
    }
  }
}];

const raw = $json;

let row = null;

if (Array.isArray(raw)) {
  row = raw[0] ?? null;
} else if (Array.isArray(raw?.data)) {
  row = raw.data[0] ?? null;
} else if (raw && typeof raw === 'object') {
  row = raw;
}

const requestId =
  row?.id ??
  $('Build Analyzing Patch').first().json.request_id;

return [{
  json: {
    ok: true,
    accepted: true,
    request_id: requestId,
    status: 'analyzing',
    message: 'تم قبول طلب توليد الاستراتيجية وبدأت المعالجة في الخلفية.'
  }
}];

const request = $('Validate Request').first().json.request;
const now = new Date().toISOString();

const source = $json ?? {};

const message =
  source.error?.message ??
  source.errorMessage ??
  source.message ??
  source.description ??
  'تعذر توليد استراتيجية الحملة.';

const nodeName =
  source.node?.name ??
  source.nodeName ??
  source.context?.nodeName ??
  null;

return [{
  json: {
    request_id: request.id,
    patch: {
      status: 'failed',
      error_code: 'STRATEGY_GENERATION_FAILED',
      error_message: nodeName
        ? `${nodeName}: ${message}`
        : String(message),
      request_payload: {
        ...(request.request_payload ?? {}),
        strategy_status: 'failed',
        strategy_failed_at: now,
        strategy_failure: {
          node: nodeName,
          message: String(message)
        },
        strategist_version: 'ws-03-async-v1'
      }
    }
  }
}];

const raw = $json;
const row = Array.isArray(raw)
  ? (raw[0] ?? null)
  : (Array.isArray(raw?.data) ? raw.data[0] : raw);

return [{
  json: {
    ok: false,
    request_id: row?.id ?? $('Build Strategy Failure Patch').first().json.request_id,
    status: row?.status ?? 'failed',
    error_code: row?.error_code ?? 'STRATEGY_GENERATION_FAILED',
    error_message: row?.error_message ?? 'تعذر توليد استراتيجية الحملة.'
  }
}];

const request = $('Validate Request').first().json.request;
const proposal = $('Parse Campaign Strategy').first().json;
const safety = $('Parse Safety Review').first().json;

const allowed = ['conservative', 'balanced', 'aggressive'];

const candidate = String(
  safety.recommended_tier ??
  proposal.recommended_tier ??
  'balanced'
).trim().toLowerCase();

const tier = allowed.includes(candidate) ? candidate : 'balanced';

return [{
  json: {
    request_id: request.id,
    tier,
    patch: {
      selected: true,
      status: 'selected'
    }
  }
}];
